import { getColorFromRule } from './get-color-from-rule.js';
import { rectDatapointMatchesColorRule } from './rect-datapoint-matches-color-rule.js';
import { ColorRuleProps } from '../../../core/types/color-rule.js';
import { safeGet } from '../../../core/utils/safe-get.js';
import { isValidCategoryValue } from '../../types/guards.js';
import type {
  ColorRuleValidator,
  MapDatapoints,
  RectSeriesWithDatapoints,
} from '../../types/xy-chart-internals.js';

export const applyColorRuleToRectSeries = (
  series: RectSeriesWithDatapoints,
  rules: ColorRuleProps[],
  isValid: ColorRuleValidator,
  datapointMetadataMap: MapDatapoints,
): Map<string, string> => {
  const categoricalColorOverrides = new Map<string, string>();

  series.data.forEach((datapoint) => {
    const matchingRule = rules.find((rule) =>
      rectDatapointMatchesColorRule(datapoint, rule, isValid),
    );

    if (matchingRule) {
      const color = getColorFromRule(matchingRule);
      if (color) {
        const metadata = safeGet(datapointMetadataMap, datapoint);
        if (metadata) {
          datapointMetadataMap.set(datapoint, {
            ...metadata,
            colorOverride: color,
          });
        }

        if (
          typeof matchingRule.matchValue === 'string' &&
          isValidCategoryValue(matchingRule.matchValue)
        ) {
          categoricalColorOverrides.set(matchingRule.matchValue, color);
        }
      }
    }
  });

  return categoricalColorOverrides;
};
